external_knowledge:
Top three most triumphant champions refers to the champions with the top three highest win rates; 
Crème de la crème refers to the best of the best, in this case the top three champions;
Mastered them refers to the summoners playing the champions.

sql:
SELECT champion_name
FROM champions
WHERE attack_damage = (SELECT MAX(attack_damage) FROM champions);

SELECT AVG(win_rate) AS average_win_rate
FROM player_engagement
WHERE champion_id = 1;

SELECT COUNT(DISTINCT player_id) AS number_of_players
FROM player_champion_mastery
WHERE champion_id = 1;

SELECT player_id, champion_id
FROM player_champion_mastery
WHERE mastery_level >= 7;

SELECT number_of_summoners_playing
FROM player_engagement
WHERE champion_id = 1;

SELECT win_rate
FROM player_engagement
WHERE total_championpoints = (
  SELECT MAX(total_championpoints)
  FROM player_engagement
);

SELECT COUNT(*) AS total_matches
  FROM player_match_history
  WHERE player_id = 1;
